  1→//! Execute instrumented Rust code via subprocess compilation.
  2→//!
  3→//! Instruments the target function, generates a `main()` harness that links
  4→//! `shatter_rust_runtime`, compiles to a binary in a temp directory, runs it,
  5→//! and parses the JSON `ExecuteResult` from stdout.
  6→
  7→use std::io;
  8→use std::path::{Path, PathBuf};
  9→use std::process::Command;
 10→use std::time::{Duration, Instant};
 11→
 12→use serde_json::Value;
 13→
 14→use crate::instrument;
 15→
 16→/// Wrap instrumented source in `mod user_code { ... }` with all top-level items
 17→/// made `pub`, so the harness `main()` can call the target function without
 18→/// name collisions (e.g. duplicate `main()` from the original source).
 19→fn wrap_in_module(source: &str) -> Result<String, ExecuteError> {
 20→    use quote::ToTokens;
 21→
 22→    let mut file = syn::parse_file(source)
 23→        .map_err(|e| ExecuteError::InstrumentError(format!("parse error: {e}")))?;
 24→
 25→    for item in &mut file.items {
 26→        match item {
 27→            syn::Item::Fn(f) => f.vis = syn::Visibility::Public(syn::token::Pub::default()),
 28→            syn::Item::Struct(s) => s.vis = syn::Visibility::Public(syn::token::Pub::default()),
 29→            syn::Item::Enum(e) => e.vis = syn::Visibility::Public(syn::token::Pub::default()),
 30→            syn::Item::Type(t) => t.vis = syn::Visibility::Public(syn::token::Pub::default()),
 31→            syn::Item::Const(c) => c.vis = syn::Visibility::Public(syn::token::Pub::default()),
 32→            syn::Item::Static(s) => s.vis = syn::Visibility::Public(syn::token::Pub::default()),
 33→            syn::Item::Trait(t) => t.vis = syn::Visibility::Public(syn::token::Pub::default()),
 34→            syn::Item::Mod(m) => m.vis = syn::Visibility::Public(syn::token::Pub::default()),
 35→            _ => {}
 36→        }
 37→    }
 38→
 39→    let tokens = file.to_token_stream().to_string();
 40→    Ok(format!("#[allow(dead_code)]\nmod user_code {{\n{tokens}\n}}"))
 41→}
 42→
 43→/// Errors from the execute pipeline.
 44→#[derive(Debug)]
 45→pub enum ExecuteError {
 46→    /// Source file not found or unreadable.
 47→    FileError(String),
 48→    /// Instrumentation failed (parse error, etc.).
 49→    InstrumentError(String),
 50→    /// Failed to write temp project files.
 51→    IoError(io::Error),
 52→    /// `cargo build` failed with compiler output.
 53→    CompilationFailed(String),
 54→    /// Binary produced no parseable output.
 55→    OutputParseError(String),
 56→    /// Function has parameters that cannot be constructed (trait objects, etc.).
 57→    NonExecutable(String),
 58→}
 59→
 60→impl std::fmt::Display for ExecuteError {
 61→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 62→        match self {
 63→            Self::FileError(e) => write!(f, "file error: {e}"),
 64→            Self::InstrumentError(e) => write!(f, "instrumentation error: {e}"),
 65→            Self::IoError(e) => write!(f, "I/O error: {e}"),
 66→            Self::CompilationFailed(e) => write!(f, "compilation failed: {e}"),
 67→            Self::OutputParseError(e) => write!(f, "output parse error: {e}"),
 68→            Self::NonExecutable(e) => write!(f, "non-executable: {e}"),
 69→        }
 70→    }
 71→}
 72→
 73→impl From<io::Error> for ExecuteError {
 74→    fn from(e: io::Error) -> Self {
 75→        Self::IoError(e)
 76→    }
 77→}
 78→
 79→/// Result of executing an instrumented function. Uses `serde_json::Value`
 80→/// for fields to stay wire-compatible without duplicating runtime types.
 81→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 82→pub struct ExecuteResult {
 83→    pub return_value: Option<Value>,
 84→    pub thrown_error: Option<Value>,
 85→    #[serde(default)]
 86→    pub branch_path: Vec<Value>,
 87→    #[serde(default)]
 88→    pub lines_executed: Vec<u32>,
 89→    #[serde(default)]
 90→    pub calls_to_external: Vec<Value>,
 91→    #[serde(default)]
 92→    pub path_constraints: Vec<Value>,
 93→    #[serde(default)]
 94→    pub side_effects: Vec<Value>,
 95→    pub performance: Value,
 96→}
 97→
 98→const DEFAULT_BUILD_TIMEOUT_SECS: u64 = 30;
 99→
100→/// Locate the shatter-rust-runtime crate by walking up from the shatter-rust binary.
101→fn find_runtime_crate_path() -> Result<PathBuf, ExecuteError> {
102→    // Try SHATTER_RUNTIME_PATH env var first (for testing and deployment).
103→    if let Ok(p) = std::env::var("SHATTER_RUNTIME_PATH") {
104→        let path = PathBuf::from(&p);
105→        if path.join("Cargo.toml").exists() {
106→            return Ok(path);
107→        }
108→    }
109→
110→    // Walk up from current exe to find shatter-rust-runtime as a sibling.
111→    if let Ok(exe) = std::env::current_exe() {
112→        let mut dir = exe.parent().map(Path::to_path_buf);
113→        for _ in 0..5 {
114→            if let Some(d) = &dir {
115→                let candidate = d.join("shatter-rust-runtime");
116→                if candidate.join("Cargo.toml").exists() {
117→                    return Ok(candidate);
118→                }
119→                dir = d.parent().map(Path::to_path_buf);
120→            }
121→        }
122→    }
123→
124→    Err(ExecuteError::FileError(
125→        "cannot locate shatter-rust-runtime crate; set SHATTER_RUNTIME_PATH".to_string(),
126→    ))
127→}
128→
129→/// Extracted function signature for harness generation.
130→struct FnSignature {
131→    param_names: Vec<String>,
132→    param_types: Vec<String>,
133→    return_type: Option<String>,
134→}
135→
136→/// Extract parameter info from a Rust source file for a specific function.
137→fn extract_fn_signature(
138→    source: &str,
139→    function_name: &str,
140→) -> Result<FnSignature, ExecuteError> {
141→    use quote::ToTokens;
142→
143→    let file = syn::parse_file(source)
144→        .map_err(|e| ExecuteError::InstrumentError(format!("parse error: {e}")))?;
145→
146→    for item in &file.items {
147→        if let syn::Item::Fn(item_fn) = item
148→            && item_fn.sig.ident == function_name
149→        {
150→            let mut param_names = Vec::new();
151→            let mut param_types = Vec::new();
152→
153→            for arg in &item_fn.sig.inputs {
154→                if let syn::FnArg::Typed(pat_type) = arg {
155→                    let name = pat_type.pat.to_token_stream().to_string();
156→                    let ty = pat_type.ty.to_token_stream().to_string();
157→                    param_names.push(name);
158→                    param_types.push(ty);
159→                }
160→            }
161→
162→            let return_type = match &item_fn.sig.output {
163→                syn::ReturnType::Default => None,
164→                syn::ReturnType::Type(_, ty) => Some(ty.to_token_stream().to_string()),
165→            };
166→
167→            return Ok(FnSignature { param_names, param_types, return_type });
168→        }
169→    }
170→
171→    Err(ExecuteError::InstrumentError(format!(
172→        "function not found: {function_name}"
173→    )))
174→}
175→
176→/// Generate a Cargo.toml for the temp project.
177→fn generate_cargo_toml(runtime_path: &Path) -> String {
178→    let runtime_path_str = runtime_path.display().to_string().replace('\\', "/");
179→    format!(
180→        r#"[package]
181→name = "shatter-exec-temp"
182→version = "0.1.0"
183→edition = "2021"
184→
185→[dependencies]
186→serde = {{ version = "1", features = ["derive"] }}
187→serde_json = "1"
188→shatter-rust-runtime = {{ path = "{runtime_path_str}" }}
189→"#
190→    )
191→}
192→
193→/// Map a reference parameter type to its owned equivalent for deserialization.
194→///
195→/// `&str` and `&String` can't be deserialized from `serde_json::Value` because
196→/// they require a borrow from the deserializer's input buffer. We deserialize
197→/// to the owned type and borrow when calling the function.
198→/// Returns true if the type string contains a trait object (`dyn Trait`).
199→/// Trait objects cannot be deserialized from JSON, so functions with such
200→/// parameters must be marked non-executable.
201→fn is_trait_object_type(ty: &str) -> bool {
202→    // Normalize spaces and check for `dyn ` keyword preceded by a word boundary.
203→    // Covers `&dyn Foo`, `Box<dyn Foo>`, `&mut dyn Foo + Bar`, etc.
204→    let normalized = ty.replace('\n', " ");
205→    normalized.contains("dyn ")
206→}
207→
208→fn owned_type_for_ref(ty: &str) -> Option<&'static str> {
209→    let normalized = ty.replace(' ', "");
210→    match normalized.as_str() {
211→        "&str" | "&'staticstr" => Some("String"),
212→        "&String" | "&'staticString" => Some("String"),
213→        _ => None,
214→    }
215→}
216→
217→/// Generate the main.rs harness that calls the target function.
218→///
219→/// Wraps instrumented source in `mod user_code` to avoid name collisions
220→/// (e.g. duplicate `fn main()` when the source file has its own `main`).
221→fn generate_harness(
222→    instrumented_source: &str,
223→    function_name: &str,
224→    param_names: &[String],
225→    param_types: &[String],
226→    return_type: Option<&str>,
227→    inputs_json: &str,
228→    mocks_json: &str,
229→) -> Result<String, ExecuteError> {
230→    let module_block = wrap_in_module(instrumented_source)?;
231→    let mut h = String::with_capacity(4096);
232→
233→    h.push_str("use serde_json::Value;\n\n");
234→    h.push_str(&module_block);
235→    h.push_str("\n\nfn main() {\n");
236→
237→    // Parse inputs
238→    h.push_str(&format!(
239→        "    let inputs_json = r#\"{}\"#;\n",
240→        inputs_json
241→    ));
242→    h.push_str(
243→        "    let inputs: Vec<Value> = serde_json::from_str(inputs_json).unwrap_or_default();\n\n",
244→    );
245→
246→    // Parse and register mocks
247→    h.push_str(&format!(
248→        "    let mocks_json = r#\"{}\"#;\n",
249→        mocks_json
250→    ));
251→    h.push_str("    let mocks: Vec<Value> = serde_json::from_str(mocks_json).unwrap_or_default();\n");
252→    h.push_str("    for mock in &mocks {\n");
253→    h.push_str("        if let (Some(symbol), Some(return_values)) = (\n");
254→    h.push_str("            mock.get(\"symbol\").and_then(|s| s.as_str()),\n");
255→    h.push_str("            mock.get(\"return_values\").and_then(|v| v.as_array()),\n");
256→    h.push_str("        ) {\n");
257→    h.push_str(
258→        "            shatter_rust_runtime::register_mock(symbol, return_values.clone());\n",
259→    );
260→    h.push_str("        }\n");
261→    h.push_str("    }\n\n");
262→
263→    // Reset runtime state
264→    h.push_str("    shatter_rust_runtime::reset();\n\n");
265→
266→    // Deserialize each input parameter.
267→    // Reference types like `&str` can't be deserialized directly — deserialize
268→    // to the owned type (e.g. `String`) and borrow in the function call.
269→    for (i, (name, ty)) in param_names.iter().zip(param_types.iter()).enumerate() {
270→        let clean_name = name.strip_prefix("mut ").unwrap_or(name).trim();
271→        if let Some(owned_ty) = owned_type_for_ref(ty) {
272→            h.push_str(&format!(
273→                "    let {clean_name}_owned: {owned_ty} = serde_json::from_value(inputs[{i}].clone()).unwrap_or_default();\n"
274→            ));
275→        } else {
276→            h.push_str(&format!(
277→                "    let {clean_name}: {ty} = serde_json::from_value(inputs[{i}].clone()).unwrap_or_default();\n"
278→            ));
279→        }
280→    }
281→    h.push('\n');
282→
283→    // Build the argument list — reference params use `&name_owned`
284→    let arg_list: Vec<String> = param_names
285→        .iter()
286→        .zip(param_types.iter())
287→        .map(|(n, ty)| {
288→            let clean = n.strip_prefix("mut ").unwrap_or(n).trim();
289→            if owned_type_for_ref(ty).is_some() {
290→                format!("&{clean}_owned")
291→            } else {
292→                clean.to_string()
293→            }
294→        })
295→        .collect();
296→    let args = arg_list.join(", ");
297→
298→    // Call the function inside catch_unwind, measuring time
299→    h.push_str("    let start = std::time::Instant::now();\n");
300→    h.push_str("    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {\n");
301→    h.push_str(&format!("        user_code::{function_name}({args})\n"));
302→    h.push_str("    }));\n");
303→    h.push_str("    let wall_time_ms = start.elapsed().as_secs_f64() * 1000.0;\n\n");
304→
305→    // Flush runtime results
306→    h.push_str(
307→        "    let runtime_json = shatter_rust_runtime::flush_results();\n",
308→    );
309→    h.push_str(
310→        "    let mut exec_result: Value = serde_json::from_str(&runtime_json).unwrap_or(Value::Object(Default::default()));\n",
311→    );
312→    h.push_str("    let obj = exec_result.as_object_mut().unwrap();\n\n");
313→
314→    // Set return_value or thrown_error
315→    h.push_str("    match result {\n");
316→    if return_type.is_some() {
317→        h.push_str("        Ok(ret_val) => {\n");
318→        h.push_str(
319→            "            obj.insert(\"return_value\".into(), serde_json::to_value(&ret_val).unwrap_or(Value::Null));\n",
320→        );
321→        h.push_str("        }\n");
322→    } else {
323→        h.push_str("        Ok(()) => {\n");
324→        h.push_str("            obj.insert(\"return_value\".into(), Value::Null);\n");
325→        h.push_str("        }\n");
326→    }
327→    h.push_str("        Err(panic_info) => {\n");
328→    h.push_str("            let msg = if let Some(s) = panic_info.downcast_ref::<&str>() {\n");
329→    h.push_str("                s.to_string()\n");
330→    h.push_str("            } else if let Some(s) = panic_info.downcast_ref::<String>() {\n");
331→    h.push_str("                s.clone()\n");
332→    h.push_str("            } else {\n");
333→    h.push_str("                format!(\"{:?}\", panic_info)\n");
334→    h.push_str("            };\n");
335→    h.push_str("            obj.insert(\"thrown_error\".into(), serde_json::json!({\n");
336→    h.push_str("                \"error_type\": \"runtime_error\",\n");
337→    h.push_str("                \"message\": msg,\n");
338→    h.push_str("            }));\n");
339→    h.push_str("        }\n");
340→    h.push_str("    }\n\n");
341→
342→    // Set performance metrics
343→    h.push_str("    obj.insert(\"performance\".into(), serde_json::json!({\n");
344→    h.push_str("        \"wall_time_ms\": wall_time_ms,\n");
345→    h.push_str("        \"cpu_time_us\": 0,\n");
346→    h.push_str("        \"heap_used_bytes\": 0,\n");
347→    h.push_str("        \"heap_allocated_bytes\": 0,\n");
348→    h.push_str("    }));\n\n");
349→
350→    // Ensure side_effects is present
351→    h.push_str("    obj.entry(\"side_effects\").or_insert(serde_json::json!([]));\n\n");
352→
353→    // Print the result JSON to stdout
354→    h.push_str("    println!(\"{}\", serde_json::to_string(&exec_result).unwrap());\n");
355→    h.push_str("}\n");
356→
357→    Ok(h)
358→}
