360→/// Execute an instrumented Rust function by compiling and running a temp project.
361→///
362→/// Returns the parsed `ExecuteResult` on success. Compilation and runtime errors
363→/// are reported as `ExecuteError` variants that the handler maps to protocol responses.
364→pub fn execute_function(
365→    file_path: &str,
366→    function_name: &str,
367→    inputs: &[Value],
368→    mocks: &[Value],
369→    timeout_ms: u64,
370→) -> Result<ExecuteResult, ExecuteError> {
371→    let path = Path::new(file_path);
372→    if !path.exists() {
373→        return Err(ExecuteError::FileError(format!(
374→            "file not found: {file_path}"
375→        )));
376→    }
377→
378→    let source = std::fs::read_to_string(path)
379→        .map_err(|e| ExecuteError::FileError(format!("cannot read {file_path}: {e}")))?;
380→
381→    // Extract function signature for harness generation
382→    let sig = extract_fn_signature(&source, function_name)?;
383→
384→    // Reject trait object parameters — they cannot be deserialized from JSON.
385→    for (name, ty) in sig.param_names.iter().zip(sig.param_types.iter()) {
386→        if is_trait_object_type(ty) {
387→            return Err(ExecuteError::NonExecutable(format!(
388→                "parameter `{name}` has trait object type `{ty}` which cannot be deserialized"
389→            )));
390→        }
391→    }
392→
393→    if inputs.len() != sig.param_names.len() {
394→        return Err(ExecuteError::InstrumentError(format!(
395→            "expected {} inputs for {function_name}, got {}",
396→            sig.param_names.len(),
397→            inputs.len()
398→        )));
399→    }
400→
401→    // Instrument the source targeting the specific function
402→    let instr_result = instrument::instrument_source(&source, Some(function_name))
403→        .map_err(|e| ExecuteError::InstrumentError(e.to_string()))?;
404→
405→    // Find the runtime crate
406→    let runtime_path = find_runtime_crate_path()?;
407→
408→    // Serialize inputs and mocks for embedding
409→    let inputs_json = serde_json::to_string(inputs)
410→        .map_err(|e| ExecuteError::InstrumentError(format!("cannot serialize inputs: {e}")))?;
411→    let mocks_json = serde_json::to_string(mocks)
412→        .map_err(|e| ExecuteError::InstrumentError(format!("cannot serialize mocks: {e}")))?;
413→
414→    // Generate the harness
415→    let harness = generate_harness(
416→        &instr_result.source,
417→        function_name,
418→        &sig.param_names,
419→        &sig.param_types,
420→        sig.return_type.as_deref(),
421→        &inputs_json,
422→        &mocks_json,
423→    )?;
424→
425→    // Create temp directory with unique name
426→    let temp_dir = std::env::temp_dir().join(format!(
427→        "shatter-exec-{}-{}",
428→        std::process::id(),
429→        std::time::SystemTime::now()
430→            .duration_since(std::time::UNIX_EPOCH)
431→            .map(|d| d.as_millis())
432→            .unwrap_or(0)
433→    ));
434→    std::fs::create_dir_all(temp_dir.join("src"))?;
435→
436→    // Write project files
437→    let cargo_toml = generate_cargo_toml(&runtime_path);
438→    std::fs::write(temp_dir.join("Cargo.toml"), cargo_toml)?;
439→    std::fs::write(temp_dir.join("src/main.rs"), &harness)?;
440→
441→    // Compile
442→    let build_timeout = Duration::from_secs(DEFAULT_BUILD_TIMEOUT_SECS);
443→    let build_start = Instant::now();
444→    let build_output = Command::new("cargo")
445→        .args(["build", "--release"])
446→        .current_dir(&temp_dir)
447→        .output()
448→        .map_err(|e| ExecuteError::CompilationFailed(format!("failed to run cargo: {e}")))?;
449→
450→    if build_start.elapsed() > build_timeout {
451→        let _ = std::fs::remove_dir_all(&temp_dir);
452→        return Err(ExecuteError::CompilationFailed(
453→            "build timed out".to_string(),
454→        ));
455→    }
456→
457→    if !build_output.status.success() {
458→        let stderr = String::from_utf8_lossy(&build_output.stderr);
459→        let _ = std::fs::remove_dir_all(&temp_dir);
460→        return Err(ExecuteError::CompilationFailed(stderr.into_owned()));
461→    }
462→
463→    // Find the compiled binary
464→    let binary_name = if cfg!(windows) {
465→        "shatter-exec-temp.exe"
466→    } else {
467→        "shatter-exec-temp"
468→    };
469→    let binary_path = temp_dir.join("target/release").join(binary_name);
470→
471→    if !binary_path.exists() {
472→        let _ = std::fs::remove_dir_all(&temp_dir);
473→        return Err(ExecuteError::CompilationFailed(
474→            "compiled binary not found".to_string(),
475→        ));
476→    }
477→
478→    // Run the binary with timeout
479→    let exec_timeout = Duration::from_millis(timeout_ms);
480→    let run_start = Instant::now();
481→    let run_output = Command::new(&binary_path)
482→        .current_dir(&temp_dir)
483→        .output()
484→        .map_err(|e| {
485→            let _ = std::fs::remove_dir_all(&temp_dir);
486→            ExecuteError::OutputParseError(format!("failed to run binary: {e}"))
487→        })?;
488→    let wall_time_ms = run_start.elapsed().as_secs_f64() * 1000.0;
489→
490→    // Clean up temp dir
491→    let _ = std::fs::remove_dir_all(&temp_dir);
492→
493→    // Check for timeout
494→    if run_start.elapsed() > exec_timeout {
495→        return Ok(ExecuteResult {
496→            return_value: None,
497→            thrown_error: Some(serde_json::json!({
498→                "error_type": "timeout",
499→                "message": format!("execution timed out after {}ms", timeout_ms),
500→            })),
501→            branch_path: vec![],
502→            lines_executed: vec![],
503→            calls_to_external: vec![],
504→            path_constraints: vec![],
505→            side_effects: vec![],
506→            performance: serde_json::json!({
507→                "wall_time_ms": wall_time_ms,
508→                "cpu_time_us": 0,
509→                "heap_used_bytes": 0,
510→                "heap_allocated_bytes": 0,
511→            }),
512→        });
513→    }
514→
515→    // Parse stdout
516→    let stdout = String::from_utf8_lossy(&run_output.stdout);
517→    let stderr_str = String::from_utf8_lossy(&run_output.stderr);
518→
519→    // Check for runtime crash (non-zero exit without output)
520→    if !run_output.status.success() && stdout.trim().is_empty() {
521→        return Ok(ExecuteResult {
522→            return_value: None,
523→            thrown_error: Some(serde_json::json!({
524→                "error_type": "runtime_error",
525→                "message": if stderr_str.is_empty() {
526→                    format!("process exited with {}", run_output.status)
527→                } else {
528→                    stderr_str.into_owned()
529→                },
530→            })),
531→            branch_path: vec![],
532→            lines_executed: vec![],
533→            calls_to_external: vec![],
534→            path_constraints: vec![],
535→            side_effects: vec![],
536→            performance: serde_json::json!({
537→                "wall_time_ms": wall_time_ms,
538→                "cpu_time_us": 0,
539→                "heap_used_bytes": 0,
540→                "heap_allocated_bytes": 0,
541→            }),
542→        });
543→    }
544→
545→    // Parse the JSON output from stdout
546→    let result: ExecuteResult = serde_json::from_str(stdout.trim()).map_err(|e| {
547→        ExecuteError::OutputParseError(format!(
548→            "failed to parse execute result: {e}\nstdout: {stdout}\nstderr: {stderr_str}"
549→        ))
550→    })?;
551→
552→    Ok(result)
553→}
